const { warehouseId, temperature, humidity } = msg.payload;

const THRESHOLDS = {
  "00000000-0000-0000-0000-000000000001": { countryName: "Brésil", idealTemp: 29, tempTolerance: 3, idealHumidity: 55, humidityTolerance: 2 },
  "00000000-0000-0000-0000-000000000002": { countryName: "Équateur", idealTemp: 31, tempTolerance: 3, idealHumidity: 60, humidityTolerance: 2 },
  "00000000-0000-0000-0000-000000000003": { countryName: "Colombie", idealTemp: 26, tempTolerance: 3, idealHumidity: 80, humidityTolerance: 2 }
};

const config = THRESHOLDS[warehouseId];
if (!config) {
  node.warn("Entrepôt inconnu : " + warehouseId);
  return null;
}

const alerts = [];
const tempMin = config.idealTemp - config.tempTolerance;
const tempMax = config.idealTemp + config.tempTolerance;
if (temperature < tempMin || temperature > tempMax) {
  alerts.push({ type: "SEUIL_TEMPERATURE", message: "Température " + temperature + "°C hors seuil [" + tempMin + "–" + tempMax + "°C] - " + config.countryName });
}

const humMin = config.idealHumidity - config.humidityTolerance;
const humMax = config.idealHumidity + config.humidityTolerance;
if (humidity < humMin || humidity > humMax) {
  alerts.push({ type: "SEUIL_HUMIDITE", message: "Humidité " + humidity + "% hors seuil [" + humMin + "–" + humMax + "%] - " + config.countryName });
}

if (alerts.length === 0) { return null; }

msg.warehouseId = warehouseId;
msg.alertTypes = alerts;
return msg;

const base = env.get('BACKEND_PAYS_URL') || 'http://host.docker.internal:3001';
msg.url = base + '/api/lots?warehouseId=' + msg.warehouseId;
return msg;

const lots = msg.payload;
const alertTypes = msg.alertTypes;

const activeLots = lots.filter(l => l.status !== 'PERIME');
if (activeLots.length === 0) { return null; }

const alertsToCreate = [];
for (const lot of activeLots) {
  for (const alertType of alertTypes) {
    alertsToCreate.push({ lotId: lot.id, type: alertType.type, message: alertType.message, lotReference: lot.reference });
  }
}

msg.payload = alertsToCreate;
return msg;

const alert = msg.payload;
const base = env.get('BACKEND_PAYS_URL') || 'http://host.docker.internal:3001';
msg.alertInfo = { type: alert.type, message: alert.message, lotReference: alert.lotReference };
msg.url = base + '/api/alerts';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = { lotId: alert.lotId, type: alert.type, message: alert.message };
return msg;

const alertInfo = msg.alertInfo;
msg.to = env.get('ALERT_EMAIL_TO') || '';
msg.topic = '[FutureKawa] Alerte : ' + alertInfo.type;
msg.payload = 'Alerte détectée pour le lot ' + alertInfo.lotReference + '

Type : ' + alertInfo.type + '
Détail : ' + alertInfo.message + '

Vérifiez le tableau de bord FutureKawa.';
return msg;

const base = env.get('BACKEND_PAYS_URL') || 'http://host.docker.internal:3001';
msg.url = base + '/api/lots';
return msg;

const lots = msg.payload;
const now = new Date();
const ONE_YEAR_MS = 365 * 24 * 60 * 60 * 1000;

const expired = lots.filter(lot => {
  if (lot.status === 'PERIME') return false;
  return (now - new Date(lot.storedAt)) > ONE_YEAR_MS;
});

if (expired.length === 0) { return null; }

msg.payload = expired.map(lot => ({
  lotId: lot.id,
  type: 'PEREMPTION',
  message: 'Lot ' + lot.reference + ' périmé — stocké depuis ' + Math.floor((now - new Date(lot.storedAt)) / (24 * 60 * 60 * 1000)) + ' jours',
  lotReference: lot.reference
}));
return msg;

const alert = msg.payload;
const base = env.get('BACKEND_PAYS_URL') || 'http://host.docker.internal:3001';
msg.alertInfo = { type: alert.type, message: alert.message, lotReference: alert.lotReference };
msg.url = base + '/api/alerts';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = { lotId: alert.lotId, type: alert.type, message: alert.message };
return msg;

const alertInfo = msg.alertInfo;
msg.to = env.get('ALERT_EMAIL_TO') || '';
msg.topic = '[FutureKawa] Lot périmé : ' + alertInfo.lotReference;
msg.payload = 'Alerte de péremption pour le lot ' + alertInfo.lotReference + '\n\n' + alertInfo.message + '\n\nVérifiez le tableau de bord FutureKawa.';
return msg;
